import{initializeApp}from"https://www.gstatic.com/firebasejs/11.6.0/firebase-app.js";import{getAuth,signInWithPopup,GoogleAuthProvider,onAuthStateChanged,signOut}from"https://www.gstatic.com/firebasejs/11.6.0/firebase-auth.js";const firebaseConfig={apiKey:"AIzaSyCJP_X6vVqXHxZYrSUAKz5cShPxWrjRBMQ",authDomain:"kucw-io-login.firebaseapp.com",projectId:"kucw-io-login",storageBucket:"kucw-io-login.firebasestorage.app",messagingSenderId:"259806144852",appId:"1:259806144852:web:713e4d7b839d84d4ea80c1"},app=initializeApp(firebaseConfig),auth=getAuth(),provider=new GoogleAuthProvider;document.getElementById("google-login-btn").addEventListener("click",async()=>{signInWithPopup(auth,provider).then(e=>{document.body.style.overflow="",document.querySelector("#login-pop-overlay").classList.remove("login-active");const t=GoogleAuthProvider.credentialFromResult(e),s=t.accessToken,n=e.user;showUserInfo(n)}).catch(e=>{console.error("登入失敗：",e.code,e.message,e.customData.email);const t=GoogleAuthProvider.credentialFromError(e)})}),onAuthStateChanged(auth,e=>{e&&showUserInfo(e)});function showUserInfo(e){const t=`
        <p><strong>使用者名稱：</strong> ${e.displayName}</p>
        <p><strong>Email：</strong> ${e.email}</p>
        <p><strong>UID：</strong> ${e.uid}</p>
        <img src="${e.photoURL}" alt="頭像" width="100" />
      `;document.getElementById("user-info").innerHTML=t}document.getElementById("sign-out-btn").addEventListener("click",async()=>{signOut(auth).then(()=>{document.getElementById("user-info").innerHTML=""}).catch(e=>{console.error("登出失敗：",e)})})